sql:
SELECT indicator_data_id
FROM indicator_data
WHERE data_value_message IS NOT NULL;

SELECT COUNT(indicator_data_id) 
FROM indicator_data 
WHERE indicator_id = 'some_indicator_id' AND year = 2005;

SELECT COUNT(*) 
FROM indicator_sources
WHERE status = 'active';

SELECT DISTINCT users.user_name
FROM users
JOIN report_access ON users.user_id = report_access.user_id;

SELECT geo_type_name
FROM geo_types
WHERE strftime('%Y', last_updated) = strftime('%Y', 'now');

SELECT outcome_name
FROM health_outcomes
WHERE prevalence_rate < 0.05;

SELECT geo_entity_name
FROM geo_entities
WHERE geo_entity_id = 1;

SELECT indicator_data_id, data_value, data_confidence_level
FROM indicator_data
ORDER BY data_value DESC;

SELECT indicator_id, geo_entity_id
FROM indicator_data
WHERE data_value > (SELECT AVG(data_value) FROM indicator_data);

SELECT g.geo_type_name, u.user_name
FROM geo_types g, users u
WHERE g.geo_type_name = 'Borough' AND u.user_name = 'Alice Johnson';

SELECT outcome_name, indicator_id
FROM health_outcomes
WHERE severity = 'High';

SELECT u.user_name, u.department
FROM users u
INNER JOIN reports r ON u.user_id = r.user_id;

SELECT id.indicator_data_id, i.name
FROM indicator_data id
JOIN indicators i ON id.indicator_id = i.indicator_id;

SELECT geo_entity_id, COUNT(DISTINCT indicator_id) AS total_indicators
FROM indicator_data
GROUP BY geo_entity_id;
